import React, { useState } from 'react';
import { Container, Row, Col, Card, Form, Button, Alert, Badge } from 'react-bootstrap';
import { useNavigate } from 'react-router-dom';

interface ProductoForm {
  nombre: string;
  sku: string;
  categoria: string;
  descripcion: string;
  precio_compra: number | string;
  precio_venta: number | string;
  stock_inicial: number | string;
  imagen_url: string;
  id_muebleria: number | string;
  material: string;
  dimensiones: string;
  peso: number | string;
  color: string;
  garantia: string;
}

export const AgregarProducto: React.FC = () => {
  const navigate = useNavigate();
  const [formData, setFormData] = useState<ProductoForm>({
    nombre: '',
    sku: '',
    categoria: '',
    descripcion: '',
    precio_compra: 0,
    precio_venta: 0,
    stock_inicial: 0,
    imagen_url: '',
    id_muebleria: 1,
    material: '',
    dimensiones: '',
    peso: 0,
    color: '',
    garantia: ''
  });

  const [showSuccess, setShowSuccess] = useState(false);
  const [showError, setShowError] = useState(false);
  const [errors, setErrors] = useState<Partial<ProductoForm>>({});

  const categorias = [
    'Sofás', 'Sillas', 'Mesas', 'Camas', 'Armarios', 'Escritorios', 
    'Librerías', 'Sillones', 'Reclinables', 'Comedores', 'Recámaras', 'Oficina'
  ];

  const materiales = [
    'Madera', 'Metal', 'Cuero', 'Tela', 'Vidrio', 'Plástico', 
    'Madera y Metal', 'Cuero Sintético', 'Tela Premium', 'Madera Sólida'
  ];

  const colores = [
    'Negro', 'Blanco', 'Marrón', 'Gris', 'Beige', 'Azul', 'Verde', 'Rojo', 'Dorado', 'Plata'
  ];

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: name === 'precio_compra' || name === 'precio_venta' || name === 'stock_inicial' || name === 'peso' 
        ? parseFloat(value) || 0 
        : name === 'id_muebleria'
        ? parseInt(value) || 1
        : value
    }));

    // Limpiar error del campo
    if (errors[name as keyof ProductoForm]) {
      setErrors(prev => ({ ...prev, [name]: undefined }));
    }
  };

  const validateForm = (): boolean => {
    const newErrors: Partial<ProductoForm> = {};

    if (!formData.nombre.trim()) newErrors.nombre = 'El nombre es requerido';
    if (!formData.sku.trim()) newErrors.sku = 'El SKU es requerido';
    if (!formData.categoria) newErrors.categoria = 'La categoría es requerida';
    if (!formData.descripcion.trim()) newErrors.descripcion = 'La descripción es requerida';
    if (typeof formData.precio_venta === 'string' ? parseFloat(formData.precio_venta) <= 0 : formData.precio_venta <= 0) newErrors.precio_venta = 'El precio de venta debe ser mayor a 0';
    if (typeof formData.stock_inicial === 'string' ? parseFloat(formData.stock_inicial) < 0 : formData.stock_inicial < 0) newErrors.stock_inicial = 'El stock no puede ser negativo';

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    if (!validateForm()) {
      setShowError(true);
      setTimeout(() => setShowError(false), 3000);
      return;
    }

    try {
      // Simulación de guardado (reemplazar con API real)
      console.log('Guardando producto:', formData);

      // Aquí iría la llamada a la API
      // await productosAPI.create(formData);

      setShowSuccess(true);
      setTimeout(() => {
        setShowSuccess(false);
        navigate('/productos');
      }, 2000);

    } catch (error) {
      console.error('Error al guardar producto:', error);
      setShowError(true);
      setTimeout(() => setShowError(false), 3000);
    }
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      // Simulación de subida de imagen
      const imageUrl = `/mueblerias/${formData.id_muebleria}/productos/${Date.now()}_${file.name}`;
      setFormData(prev => ({ ...prev, imagen_url: imageUrl }));
    }
  };

  return (
    <div style={{ 
      background: 'var(--primary-gradient)', 
      minHeight: '100vh', 
      paddingTop: '60px',
      paddingBottom: '60px'
    }}>
      <Container>
        <Row className="justify-content-center">
          <Col lg={10}>
            <Card className="border-0" style={{ 
              borderRadius: '24px',
              boxShadow: '0 20px 60px rgba(0,0,0,0.15)',
              overflow: 'hidden'
            }}>
              <div style={{
                background: 'var(--accent-gradient)',
                padding: '30px 40px',
                borderBottom: '1px solid var(--border-color)'
              }}>
                <div className="text-center">
                  <div style={{
                    width: '70px',
                    height: '70px',
                    background: 'white',
                    borderRadius: '50%',
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'center',
                    margin: '0 auto 20px',
                    boxShadow: '0 4px 15px rgba(0,0,0,0.1)'
                  }}>
                    <i className="bi bi-plus-circle" style={{ 
                      fontSize: '2rem', 
                      color: 'var(--primary-color)'
                    }}></i>
                  </div>
                  <h2 style={{ 
                    color: 'var(--text-primary)', 
                    fontWeight: '700',
                    marginBottom: '10px',
                    fontSize: '2rem'
                  }}>
                    Agregar Nuevo Producto
                  </h2>
                  <p className="mb-0" style={{ 
                    color: 'var(--text-secondary)',
                    fontSize: '1.1rem'
                  }}>
                    Completa el formulario para agregar un producto al inventario
                  </p>
                </div>
              </div>
              <Card.Body className="p-5">

                {showSuccess && (
                  <Alert variant="success" className="mb-4">
                    <i className="bi bi-check-circle"></i> Producto agregado exitosamente
                  </Alert>
                )}

                {showError && (
                  <Alert variant="danger" className="mb-4">
                    <i className="bi bi-exclamation-triangle"></i> Error al agregar el producto. Por favor, revise los campos.
                  </Alert>
                )}

                <Form onSubmit={handleSubmit}>
                  <Row>
                    {/* Información Básica */}
                    <Col lg={6}>
                      <h5 className="mb-3" style={{ color: 'var(--accent-color)' }}>
                        <i className="bi bi-info-circle"></i> Información Básica
                      </h5>

                      <Form.Group className="mb-3">
                        <Form.Label className="fw-semibold">Nombre del Producto *</Form.Label>
                        <Form.Control
                          type="text"
                          name="nombre"
                          value={formData.nombre}
                          onChange={handleChange}
                          isInvalid={!!errors.nombre}
                          placeholder="Ej: Sofá Moderno de 3 Plazas"
                        />
                        <Form.Control.Feedback type="invalid">
                          {errors.nombre}
                        </Form.Control.Feedback>
                      </Form.Group>

                      <Form.Group className="mb-3">
                        <Form.Label className="fw-semibold">SKU *</Form.Label>
                        <Form.Control
                          type="text"
                          name="sku"
                          value={formData.sku}
                          onChange={handleChange}
                          isInvalid={!!errors.sku}
                          placeholder="Ej: SOF-001-MOD"
                        />
                        <Form.Control.Feedback type="invalid">
                          {errors.sku}
                        </Form.Control.Feedback>
                      </Form.Group>

                      <Form.Group className="mb-3">
                        <Form.Label className="fw-semibold">Categoría *</Form.Label>
                        <Form.Select
                          name="categoria"
                          value={formData.categoria}
                          onChange={handleChange}
                          isInvalid={!!errors.categoria}
                        >
                          <option value="">Selecciona una categoría</option>
                          {categorias.map(cat => (
                            <option key={cat} value={cat}>{cat}</option>
                          ))}
                        </Form.Select>
                        <Form.Control.Feedback type="invalid">
                          {errors.categoria}
                        </Form.Control.Feedback>
                      </Form.Group>

                      <Form.Group className="mb-3">
                        <Form.Label className="fw-semibold">Descripción *</Form.Label>
                        <Form.Control
                          as="textarea"
                          rows={3}
                          name="descripcion"
                          value={formData.descripcion}
                          onChange={handleChange}
                          isInvalid={!!errors.descripcion}
                          placeholder="Describe las características principales del producto..."
                        />
                        <Form.Control.Feedback type="invalid">
                          {errors.descripcion}
                        </Form.Control.Feedback>
                      </Form.Group>
                    </Col>

                    {/* Información de Precios y Stock */}
                    <Col lg={6}>
                      <h5 className="mb-3" style={{ color: 'var(--accent-color)' }}>
                        <i className="bi bi-currency-dollar"></i> Precios y Stock
                      </h5>

                      <Row>
                        <Col md={6}>
                          <Form.Group className="mb-3">
                            <Form.Label className="fw-semibold">Precio de Compra</Form.Label>
                            <Form.Control
                              type="number"
                              step="0.01"
                              name="precio_compra"
                              value={formData.precio_compra}
                              onChange={handleChange}
                              placeholder="0.00"
                            />
                          </Form.Group>
                        </Col>
                        <Col md={6}>
                          <Form.Group className="mb-3">
                            <Form.Label className="fw-semibold">Precio de Venta *</Form.Label>
                            <Form.Control
                              type="number"
                              step="0.01"
                              name="precio_venta"
                              value={formData.precio_venta}
                              onChange={handleChange}
                              isInvalid={!!errors.precio_venta}
                              placeholder="0.00"
                            />
                            <Form.Control.Feedback type="invalid">
                              {errors.precio_venta}
                            </Form.Control.Feedback>
                          </Form.Group>
                        </Col>
                      </Row>

                      <Form.Group className="mb-3">
                        <Form.Label className="fw-semibold">Stock Inicial *</Form.Label>
                        <Form.Control
                          type="number"
                          name="stock_inicial"
                          value={formData.stock_inicial}
                          onChange={handleChange}
                          isInvalid={!!errors.stock_inicial}
                          placeholder="0"
                        />
                        <Form.Control.Feedback type="invalid">
                          {errors.stock_inicial}
                        </Form.Control.Feedback>
                      </Form.Group>

                      <Form.Group className="mb-3">
                        <Form.Label className="fw-semibold">ID Mueblería</Form.Label>
                        <Form.Control
                          type="number"
                          name="id_muebleria"
                          value={formData.id_muebleria}
                          onChange={handleChange}
                          placeholder="1"
                        />
                      </Form.Group>

                      <Form.Group className="mb-3">
                        <Form.Label className="fw-semibold">URL de Imagen</Form.Label>
                        <Form.Control
                          type="text"
                          name="imagen_url"
                          value={formData.imagen_url}
                          onChange={handleChange}
                          placeholder="/mueblerias/1/producto.jpg"
                        />
                      </Form.Group>

                      <Form.Group className="mb-3">
                        <Form.Label className="fw-semibold">Subir Imagen</Form.Label>
                        <Form.Control
                          type="file"
                          accept="image/*"
                          onChange={handleImageUpload}
                        />
                        <Form.Text className="text-muted">
                          Formatos permitidos: JPG, PNG, GIF. Máximo 5MB.
                        </Form.Text>
                      </Form.Group>
                    </Col>
                  </Row>

                  <Row className="mt-4">
                    {/* Características Físicas */}
                    <Col lg={6}>
                      <h5 className="mb-3" style={{ color: 'var(--accent-color)' }}>
                        <i className="bi bi-box"></i> Características Físicas
                      </h5>

                      <Form.Group className="mb-3">
                        <Form.Label className="fw-semibold">Material</Form.Label>
                        <Form.Select
                          name="material"
                          value={formData.material}
                          onChange={handleChange}
                        >
                          <option value="">Selecciona un material</option>
                          {materiales.map(mat => (
                            <option key={mat} value={mat}>{mat}</option>
                          ))}
                        </Form.Select>
                      </Form.Group>

                      <Form.Group className="mb-3">
                        <Form.Label className="fw-semibold">Dimensiones</Form.Label>
                        <Form.Control
                          type="text"
                          name="dimensiones"
                          value={formData.dimensiones}
                          onChange={handleChange}
                          placeholder="Ej: 200cm x 80cm x 90cm"
                        />
                      </Form.Group>

                      <Form.Group className="mb-3">
                        <Form.Label className="fw-semibold">Peso (kg)</Form.Label>
                        <Form.Control
                          type="number"
                          step="0.1"
                          name="peso"
                          value={formData.peso}
                          onChange={handleChange}
                          placeholder="0.0"
                        />
                      </Form.Group>
                    </Col>

                    {/* Información Adicional */}
                    <Col lg={6}>
                      <h5 className="mb-3" style={{ color: 'var(--accent-color)' }}>
                        <i className="bi bi-gear"></i> Información Adicional
                      </h5>

                      <Form.Group className="mb-3">
                        <Form.Label className="fw-semibold">Color</Form.Label>
                        <Form.Select
                          name="color"
                          value={formData.color}
                          onChange={handleChange}
                        >
                          <option value="">Selecciona un color</option>
                          {colores.map(col => (
                            <option key={col} value={col}>{col}</option>
                          ))}
                        </Form.Select>
                      </Form.Group>

                      <Form.Group className="mb-3">
                        <Form.Label className="fw-semibold">Garantía</Form.Label>
                        <Form.Control
                          type="text"
                          name="garantia"
                          value={formData.garantia}
                          onChange={handleChange}
                          placeholder="Ej: 2 años"
                        />
                      </Form.Group>
                    </Col>
                  </Row>

                  {/* Botones de Acción */}
                  <div className="d-flex justify-content-between mt-4">
                    <Button 
                      variant="outline-secondary" 
                      onClick={() => navigate('/productos')}
                      style={{ borderRadius: '30px', padding: '0.8rem 2rem' }}
                    >
                      <i className="bi bi-arrow-left"></i> Cancelar
                    </Button>

                    <div className="d-flex gap-2">
                      <Button 
                        variant="outline-primary" 
                        type="button"
                        style={{ borderRadius: '30px', padding: '0.8rem 2rem' }}
                      >
                        <i className="bi bi-save"></i> Guardar Borrador
                      </Button>

                      <Button 
                        variant="primary" 
                        type="submit"
                        style={{ 
                          borderRadius: '30px', 
                          padding: '0.8rem 2rem',
                          background: 'var(--accent-gradient)',
                          border: 'none'
                        }}
                      >
                        <i className="bi bi-check-circle"></i> Agregar Producto
                      </Button>
                    </div>
                  </div>
                </Form>
              </Card.Body>
            </Card>
          </Col>
        </Row>
      </Container>
    </div>
  );
};
